<?php
namespace App\Models;
use Illuminate\Database\Eloquent\Model; use Illuminate\Database\Eloquent\Relations\{BelongsTo,HasMany};
class TravelRoute extends Model { protected $fillable=['name','origin_location_id','destination_location_id','estimated_minutes','status']; public function origin(): BelongsTo { return $this->belongsTo(Location::class,'origin_location_id'); } public function destination(): BelongsTo { return $this->belongsTo(Location::class,'destination_location_id'); } public function stops(): HasMany { return $this->hasMany(RouteStop::class)->orderBy('stop_order'); } public function charges(): HasMany { return $this->hasMany(RouteCharge::class); } public function schedules(): HasMany { return $this->hasMany(TravelSchedule::class); } public function bookings(): HasMany { return $this->hasMany(Booking::class); } }
